local ActivityModelToUiName = ActivityModelToUiName

local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxActivityCtrl:LxBaseCtrl
local LxActivityCtrl = classX("LxActivityCtrl", LxBaseCtrl)

function LxActivityCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxActivityCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

-- 打开活动
function LxActivityCtrl:OpenActivity(refId)
    local data =  ModuleCenter.Activity:GetData(refId)
    if not data then
        assert(nil, "不存在活动数据：" .. tostring(refId))
        return
    end
    local uiName = ActivityModelToUiName[data.model]
    assert(uiName, "请添加活动对应的ui， model = " .. tostring(data.model))

    ShowPanel(UiNames.ActivityFrame, {refId = refId})
end

-- 请求http获取活动配置
function LxActivityCtrl:SendGetActivityRef(refId)
    local data = ModuleCenter.Activity:GetData(refId)
    if not data then
        return
    end
    local verifyTime = data.verifyTime

    local webConfig = ModuleCenter.Activity:InnerGetWebConfig(refId)
    if webConfig and webConfig:IsValidCheck(verifyTime) then
        return
    end

    if webConfig then
        if webConfig:IsNeedResend() then
            webConfig:ReStartWebConfig()
            return
        end
        webConfig:Dispose()
    end

    webConfig = require("LApp.module.activity.LxActivityWebConfig"):new()
    ModuleCenter.Activity:SetRef(refId, webConfig)

    webConfig:Initialize(refId, verifyTime)
    webConfig:StartGetConfig()
end

return LxActivityCtrl
